  beforeEach(() => {
    jest.clearAllMocks();
  });

  test('Criar usuário, atualizar nome e email, verificar dados atualizados, tentar atualizar com email duplicado, deletar e verificar inexistência', async () => {
    const userId = 1;
    const initialUser = { id: userId, name: 'Nome Inicial', email: 'email@exemplo.com' };
    const createdUser = { ...initialUser };
    const updatedUser = { id: userId, name: 'Nome Atualizado', email: 'novoemail@exemplo.com' };
    const conflictingUser = { id: 2, name: 'Outro', email: 'emailduplicado@exemplo.com' };

    // Mock createUser
    userService.findByEmail.mockImplementation(email => {
      if (email === initialUser.email) return null;
      if (email === conflictingUser.email) return conflictingUser;
      return null;
    });
    userService.createUser.mockReturnValue(createdUser);

    // Criar usuário
    const createResponse = await request(app)
      .post('/users')
      .send({ name: initialUser.name, email: initialUser.email });

    expect(createResponse.status).toBe(201);
    expect(createResponse.body).toEqual(createdUser);

    // Mock updateUser and findByEmail for update
    userService.findByEmail.mockImplementation(email => {
      if (email === conflictingUser.email) return conflictingUser;
      if (email === updatedUser.email) return null;
      return null;
    });
    userService.updateUser.mockImplementation((id, data) => {
      if (id !== userId) return null;
      return { id, name: data.name || initialUser.name, email: data.email || initialUser.email };
    });
    userService.getUser.mockImplementation(id => {
      if (id === userId) return updatedUser;
      return null;
    });

    // Atualizar nome e email
    const updateResponse = await request(app)
      .put(`/users/${userId}`)
      .send({ name: updatedUser.name, email: updatedUser.email });

    expect(updateResponse.status).toBe(200);
    expect(updateResponse.body).toEqual(updatedUser);

    // Verificar via GET se dados foram atualizados
    const getResponse = await request(app)
      .get(`/users/${userId}`);

    expect(getResponse.status).toBe(200);
    expect(getResponse.body).toEqual(updatedUser);

    // Tentar atualizar com email duplicado
    userService.findByEmail.mockReturnValue(conflictingUser);

    const conflictResponse = await request(app)
      .put(`/users/${userId}`)
      .send({ email: conflictingUser.email });

    expect(conflictResponse.status).toBe(409);
    expect(conflictResponse.body).toEqual({ detail: 'E-mail já cadastrado por outro usuário' });

    // Mock deleteUser and getUser for deletion
    userService.getUser.mockReturnValue(updatedUser);
    userService.deleteUser.mockReturnValue(true);

    // Deletar usuário
    const deleteResponse = await request(app)
      .delete(`/users/${userId}`);

    expect(deleteResponse.status).toBe(204);

    // Após exclusão, getUser retorna null
    userService.getUser.mockReturnValue(null);

    const getAfterDeleteResponse = await request(app)
      .get(`/users/${userId}`);

    expect(getAfterDeleteResponse.status).toBe(404);
    expect(getAfterDeleteResponse.body).toEqual({ detail: 'Usuário não encontrado' });
  });
});

